msg.operation = 'readmultiple';
msg.items = [
    { nodeId: 'ns=1;s=Scalar.Int32', name: 'MyInt' },
    { nodeId: 'ns=1;s=Scalar.Double', name: 'MyDouble' },
    { nodeId: 'ns=1;s=Scalar.Boolean', name: 'MyBool' },
    { nodeId: 'ns=1;s=Scalar.String', name: 'MyString' }
];
return msg;

// Object-Format: Key = friendly name, Value = nodeId string
msg.operation = 'readmultiple';
msg.payload = {
    "Temperature": "ns=1;s=Writable.Temperature",
    "Pressure": "ns=1;s=Writable.Pressure",
    "Counter": "ns=1;s=Writable.Counter",
    "MachineName": "ns=1;s=Writable.MachineName"
};
return msg;

msg.operation = 'writemultiple';
msg.items = [
    { nodeId: 'ns=1;s=Writable.Temperature', value: 22.5, datatype: 'Double' },
    { nodeId: 'ns=1;s=Writable.Pressure', value: 1013.25, datatype: 'Double' },
    { nodeId: 'ns=1;s=Writable.Active', value: true, datatype: 'Boolean' },
    { nodeId: 'ns=1;s=Writable.MachineName', value: 'BatchWrite-Test', datatype: 'String' },
    { nodeId: 'ns=1;s=Writable.Counter', value: 999, datatype: 'Int32' }
];
return msg;

// Object-Format: Key = nodeId, Value = {value, datatype}
msg.operation = 'writemultiple';
msg.payload = {
    "ns=1;s=Writable.Temperature": { value: 28.5, datatype: "Double" },
    "ns=1;s=Writable.Pressure": { value: 1015.0, datatype: "Double" },
    "ns=1;s=Writable.Counter": { value: 500, datatype: "Int32" },
    "ns=1;s=Writable.MachineName": { value: "PayloadWrite-Test", datatype: "String" }
};
return msg;

// Values from writeValues map to items by name
const vals = msg.writeValues || {};
if (msg.items) {
    msg.items.forEach(item => {
        if (vals[item.itemName] !== undefined) {
            item.value = vals[item.itemName];
        }
    });
}
return msg;

msg.operation = 'history';
msg.nodeId = 'ns=1;s=Dynamic.Sinus';
msg.startTime = new Date(Date.now() - 3600000); // 1 hour ago
msg.endTime = new Date();
msg.maxValues = 100;
return msg;

msg.operation = 'history';
msg.nodeId = 'ns=1;s=Dynamic.Random';
msg.payload = {
    startTime: new Date(Date.now() - 7200000), // 2 hours
    endTime: new Date()
};
msg.maxValues = 500;
return msg;

// Only process read results for Counter
if (msg.operation === 'read' && msg.nodeId === 'ns=1;s=Writable.Counter') {
    msg.operation = 'write';
    msg.payload = (msg.payload || 0) + 1;
    msg.datatype = 'Int32';
    return msg;
}
return null;

// Only process read results for Temperature
if (msg.operation === 'read' && msg.nodeId === 'ns=1;s=Writable.Temperature') {
    if (msg.payload > 30) {
        msg.operation = 'write';
        msg.payload = 20.0;
        msg.datatype = 'Double';
        return msg;
    }
}
return null;

msg.operation = 'readmultiple';
msg.items = [
    { nodeId: 'ns=1;s=Machine.Motor.Speed', name: 'Motor Speed' },
    { nodeId: 'ns=1;s=Machine.Motor.Current', name: 'Motor Current' },
    { nodeId: 'ns=1;s=Machine.Motor.Temperature', name: 'Motor Temp' },
    { nodeId: 'ns=1;s=Machine.Motor.Running', name: 'Motor Running' },
    { nodeId: 'ns=1;s=Machine.Pump.FlowRate', name: 'Pump Flow' },
    { nodeId: 'ns=1;s=Machine.Pump.Pressure', name: 'Pump Pressure' },
    { nodeId: 'ns=1;s=Machine.Pump.ValveOpen', name: 'Valve Open' },
    { nodeId: 'ns=1;s=Machine.Sensors.AmbientTemp', name: 'Ambient Temp' },
    { nodeId: 'ns=1;s=Machine.Sensors.Humidity', name: 'Humidity' },
    { nodeId: 'ns=1;s=Machine.Sensors.Vibration', name: 'Vibration' }
];
return msg;

// Show endpoint details with auth tokens
var eps = msg.payload || [];
var summary = eps.map(function(ep) {
    var tokens = (ep.userIdentityTokens || []).map(function(t) {
        var types = { 0: 'Anonymous', 1: 'Username', 2: 'Certificate', 3: 'IssuedToken' };
        return types[t.tokenType] || 'Type-' + t.tokenType;
    });
    return {
        url: ep.endpointUrl,
        securityMode: ep.securityMode,
        securityPolicy: ep.securityPolicy,
        authMethods: tokens
    };
});
msg.payload = summary;
msg.endpointCount = eps.length;
return msg;

var eps = msg.payload || [];
var tokenTypes = {0:'Anonymous',1:'Username',2:'X509 Cert',3:'IssuedToken'};
msg.payload = {
    totalEndpoints: eps.length,
    endpoints: eps.map(function(ep){
        return {
            mode: ep.securityMode,
            policy: ep.securityPolicy,
            auth: (ep.userIdentityTokens||[]).map(function(t){return tokenTypes[t.tokenType]||t.tokenType;})
        };
    })
};
return msg;

msg = {
    operation: "write",
    nodeId: "ns=1;s=Structure.SensorReading",
